public struct FfiConverterTypeVikerEditor: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = VikerEditor

    public static func lift(_ handle: UInt64) throws -> VikerEditor {
        return VikerEditor(unsafeFromHandle: handle)
    }

    public static func lower(_ value: VikerEditor) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> VikerEditor {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: VikerEditor, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


