    case text
    case keyword
    case typeName
    case tag
    case attribute
    case constructor
    case function
    case method
    case macro
    case stringLiteral
    case escape
    case character
    case numberLiteral
    case booleanLiteral
    case constant
    case comment
    case variable
    case parameter
    case property
    case module
    case label
    case punctuation
    case operatorToken
    case heading
    case rawText
    case link
    case linkUrl
    case emphasis
    case strong
    case unknown





}

#if compiler(>=6)
extension VikerSyntaxToken: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeVikerSyntaxToken: FfiConverterRustBuffer {
    typealias SwiftType = VikerSyntaxToken

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> VikerSyntaxToken {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .text
        
        case 2: return .keyword
        
        case 3: return .typeName
        
        case 4: return .tag
        
        case 5: return .attribute
        
        case 6: return .constructor
        
        case 7: return .function
        
        case 8: return .method
        
        case 9: return .macro
        
        case 10: return .stringLiteral
        
        case 11: return .escape
        
        case 12: return .character
        
        case 13: return .numberLiteral
        
        case 14: return .booleanLiteral
        
        case 15: return .constant
        
        case 16: return .comment
        
        case 17: return .variable
        
        case 18: return .parameter
        
        case 19: return .property
        
        case 20: return .module
        
        case 21: return .label
        
        case 22: return .punctuation
        
        case 23: return .operatorToken
        
        case 24: return .heading
        
        case 25: return .rawText
        
        case 26: return .link
        
        case 27: return .linkUrl
        
        case 28: return .emphasis
        
        case 29: return .strong
        
        case 30: return .unknown
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: VikerSyntaxToken, into buf: inout [UInt8]) {
        switch value {
        
        
        case .text:
            writeInt(&buf, Int32(1))
        
        
        case .keyword:
            writeInt(&buf, Int32(2))
        
        
        case .typeName:
            writeInt(&buf, Int32(3))
        
        
        case .tag:
            writeInt(&buf, Int32(4))
        
        
        case .attribute:
            writeInt(&buf, Int32(5))
        
        
        case .constructor:
            writeInt(&buf, Int32(6))
        
        
        case .function:
            writeInt(&buf, Int32(7))
        
        
        case .method:
            writeInt(&buf, Int32(8))
        
        
        case .macro:
            writeInt(&buf, Int32(9))
        
        
        case .stringLiteral:
            writeInt(&buf, Int32(10))
        
        
        case .escape:
            writeInt(&buf, Int32(11))
        
        
        case .character:
            writeInt(&buf, Int32(12))
        
        
        case .numberLiteral:
            writeInt(&buf, Int32(13))
        
        
        case .booleanLiteral:
            writeInt(&buf, Int32(14))
        
        
        case .constant:
            writeInt(&buf, Int32(15))
        
        
        case .comment:
            writeInt(&buf, Int32(16))
        
        
        case .variable:
            writeInt(&buf, Int32(17))
        
        
        case .parameter:
            writeInt(&buf, Int32(18))
        
        
        case .property:
            writeInt(&buf, Int32(19))
        
        
        case .module:
            writeInt(&buf, Int32(20))
        
        
        case .label:
            writeInt(&buf, Int32(21))
        
        
        case .punctuation:
            writeInt(&buf, Int32(22))
        
        
        case .operatorToken:
            writeInt(&buf, Int32(23))
        
        
        case .heading:
            writeInt(&buf, Int32(24))
        
        
        case .rawText:
            writeInt(&buf, Int32(25))
        
        
        case .link:
            writeInt(&buf, Int32(26))
        
        
        case .linkUrl:
            writeInt(&buf, Int32(27))
        
        
        case .emphasis:
            writeInt(&buf, Int32(28))
        
        
        case .strong:
            writeInt(&buf, Int32(29))
        
        
        case .unknown:
            writeInt(&buf, Int32(30))
        
        }
    }
}


